'use strict';
/**
 * migrate-to-base-crud-service.js
 * ════════════════════════════════
 * Migrates class-based DDD services (Pattern A + B) to extend BaseCrudService.
 *
 * Changes per file:
 * 1. Import BaseCrudService (replace BaseDomainModule if present, or add new)
 * 2. Change extends clause to BaseCrudService
 * 3. Add model registration in constructor
 * 4. Remove healthCheck() method (auto-generated by BaseCrudService)
 * 5. Collapse multi-line standard CRUD methods to helper calls
 *
 * Usage:
 *   node scripts/migrate-to-base-crud-service.js              # dry run
 *   node scripts/migrate-to-base-crud-service.js --apply       # apply changes
 *   node scripts/migrate-to-base-crud-service.js --apply --file dddAccreditationManager.js  # single file
 */

const fs = require('fs');
const path = require('path');

const SERVICES_DIR = path.join(__dirname, '..', 'backend', 'services');
const DRY_RUN = !process.argv.includes('--apply');
const SINGLE_FILE = process.argv.find((a, i) => process.argv[i - 1] === '--file');

// ═══════════════ Helpers ═══════════════

function getModelNames(code) {
  // Extract model variable names from the require('../models/DddXxx') destructure
  const match = code.match(/const\s*\{([^}]+)\}\s*=\s*require\s*\(['"]\.\.\/models\//s);
  if (!match) return { models: [], constants: [] };

  const items = match[1]
    .split(',')
    .map(s => s.trim())
    .filter(Boolean);
  const models = [];
  const constants = [];

  for (const item of items) {
    if (/^DDD[A-Z]/.test(item) || /^[A-Z][a-z]/.test(item)) {
      // Heuristic: ALL_CAPS or UPPER_SNAKE = constant, else = model
      if (/^[A-Z_]+$/.test(item) || /^[A-Z]+_[A-Z_]+/.test(item)) {
        constants.push(item);
      } else {
        models.push(item);
      }
    } else if (/^[A-Z_]+$/.test(item)) {
      constants.push(item);
    } else {
      constants.push(item);
    }
  }
  return { models, constants };
}

function buildModelRegistry(models) {
  // Convert model names to registry keys
  // DDDAccreditationCycle → cycles, DDDAnnouncement → announcements
  const entries = [];
  for (const m of models) {
    const clean = m.replace(/^DDD/, '');
    // Simple pluralization: camelCase + 's'
    const key = clean.charAt(0).toLowerCase() + clean.slice(1) + 's';
    entries.push(`      ${key}: ${m}`);
  }
  return entries.join(',\n');
}

function removeHealthCheck(code) {
  // Remove healthCheck method — match from 'async healthCheck()' to the closing '}'
  // This is tricky because of nested braces. Use a counter approach.
  const hcStart = code.search(/\n\s*async\s+healthCheck\s*\(\)\s*\{/);
  if (hcStart === -1) return { code, removed: false, linesRemoved: 0 };

  // Find the line before async healthCheck (may be a comment like /* ── Health ── */)
  const beforeHC = code.lastIndexOf('\n', hcStart - 1);
  let searchStart = hcStart;

  // Check for preceding comment block (/* ── Health ── */ or similar)
  const linesBefore = code.substring(Math.max(0, hcStart - 120), hcStart);
  const commentMatch = linesBefore.match(/\n(\s*\/\*[^}]*?\*\/\s*\n?)$/s);
  if (commentMatch) {
    searchStart = hcStart - commentMatch[1].length;
  }

  // Find opening brace
  const braceStart = code.indexOf('{', hcStart);
  if (braceStart === -1) return { code, removed: false, linesRemoved: 0 };

  // Count braces to find the closing one
  let depth = 0;
  let i = braceStart;
  for (; i < code.length; i++) {
    if (code[i] === '{') depth++;
    if (code[i] === '}') {
      depth--;
      if (depth === 0) break;
    }
  }

  if (depth !== 0) return { code, removed: false, linesRemoved: 0 };

  const removed = code.substring(searchStart, i + 1);
  const linesRemoved = removed.split('\n').length;
  const newCode = code.substring(0, searchStart) + code.substring(i + 1);

  return { code: newCode, removed: true, linesRemoved };
}

function collapseStandardCreate(code) {
  // Pattern: async createXxx(data) { return Model.create(data); }
  // No change needed — already single line. But normalize spacing:
  let count = 0;
  code = code.replace(/async\s+(\w+)\(data\)\s*\{\s*return\s+(\w+)\.create\(data\);\s*\}/g, (match, method, model) => {
    count++;
    return `async ${method}(data) { return this._create(${model}, data); }`;
  });
  return { code, count };
}

function collapseStandardGetById(code) {
  // Pattern: async getXxx(id) { return Model.findById(id).lean(); }
  let count = 0;
  code = code.replace(/async\s+(\w+)\(id\)\s*\{\s*return\s+(\w+)\.findById\(id\)\.lean\(\);\s*\}/g, (match, method, model) => {
    count++;
    return `async ${method}(id) { return this._getById(${model}, id); }`;
  });
  return { code, count };
}

function collapseStandardUpdate(code) {
  // Pattern 1: async updateXxx(id, data) { return Model.findByIdAndUpdate(id, data, { new: true }).lean(); }
  let count = 0;
  code = code.replace(
    /async\s+(\w+)\(id,\s*data\)\s*\{\s*return\s+(\w+)\.findByIdAndUpdate\(id,\s*data,\s*\{\s*new:\s*true\s*\}\)\.lean\(\);\s*\}/g,
    (match, method, model) => {
      count++;
      return `async ${method}(id, data) { return this._update(${model}, id, data); }`;
    },
  );
  // Pattern 2: with runValidators
  code = code.replace(
    /async\s+(\w+)\(id,\s*data\)\s*\{\s*return\s+(\w+)\.findByIdAndUpdate\(id,\s*data,\s*\{\s*new:\s*true,\s*runValidators:\s*true\s*\}\)\.lean\(\);\s*\}/g,
    (match, method, model) => {
      count++;
      return `async ${method}(id, data) { return this._update(${model}, id, data, { runValidators: true }); }`;
    },
  );
  return { code, count };
}

function collapseMultiLineList(code) {
  // Pattern: multi-line find().sort().lean() — non-paginated
  let count = 0;

  // Pattern 1: Multi-line with filter parameter — Model.find(filter)\n.sort({...})\n.lean()
  code = code.replace(
    /async\s+(\w+)\((filter|filters|f)\s*=\s*\{\}\)\s*\{\s*\n\s*return\s+(\w+)\.find\(\2\)\s*\n\s*\.sort\((\{[^}]+\})\)\s*\n\s*\.lean\(\);\s*\n\s*\}/g,
    (match, method, param, model, sort) => {
      count++;
      if (sort.trim() === '{ createdAt: -1 }') {
        return `async ${method}(${param} = {}) { return this._list(${model}, ${param}); }`;
      }
      return `async ${method}(${param} = {}) { return this._list(${model}, ${param}, { sort: ${sort} }); }`;
    },
  );

  // Pattern 2: Multi-line paginated — find(filter).sort({...}).skip(...).limit(...).lean()
  code = code.replace(
    /async\s+(\w+)\((filter|filters|f)\s*=\s*\{\},\s*(page)\s*=\s*1,\s*(limit)\s*=\s*(\d+)\)\s*\{\s*\n\s*return\s+(\w+)\.find\(\2\)\s*\n\s*\.sort\((\{[^}]+\})\)\s*\n\s*\.skip\(\(\3\s*-\s*1\)\s*\*\s*\4\)\s*\n\s*\.limit\(\4\)\s*\n\s*\.lean\(\);\s*\n\s*\}/g,
    (match, method, filterParam, pageParam, limitParam, defLimit, model, sort) => {
      count++;
      return `async ${method}(${filterParam} = {}, ${pageParam} = 1, ${limitParam} = ${defLimit}) { return this._list(${model}, ${filterParam}, { page: ${pageParam}, limit: ${limitParam}, sort: ${sort} }); }`;
    },
  );

  // Pattern 3: Single-line find(filter).sort({...}).lean()
  code = code.replace(
    /async\s+(\w+)\((filter|filters|f)\s*=\s*\{\}\)\s*\{\s*return\s+(\w+)\.find\(\2\)\.sort\((\{[^}]+\})\)\.lean\(\);\s*\}/g,
    (match, method, param, model, sort) => {
      count++;
      if (sort.trim() === '{ createdAt: -1 }') {
        return `async ${method}(${param} = {}) { return this._list(${model}, ${param}); }`;
      }
      return `async ${method}(${param} = {}) { return this._list(${model}, ${param}, { sort: ${sort} }); }`;
    },
  );

  // Pattern 4: No-arg list — find({}).sort({...}).lean() or find({ isActive: true }).sort(...)
  code = code.replace(
    /async\s+(\w+)\(\)\s*\{\s*\n?\s*return\s+(\w+)\.find\((\{[^}]*\})\)\.sort\((\{[^}]+\})\)\.lean\(\);\s*\n?\s*\}/g,
    (match, method, model, filter, sort) => {
      count++;
      return `async ${method}() { return this._list(${model}, ${filter}, { sort: ${sort} }); }`;
    },
  );

  return { code, count };
}

function addBaseCrudServiceImport(code, isPatternA) {
  if (isPatternA) {
    // Replace BaseDomainModule import with BaseCrudService
    code = code.replace(
      /const\s+BaseDomainModule\s*=\s*require\s*\(['"]\.\/base\/BaseDomainModule['"]\);?/,
      "const BaseCrudService = require('./base/BaseCrudService');",
    );
    // Replace extends BaseDomainModule with extends BaseCrudService
    code = code.replace(/extends\s+BaseDomainModule\s*\{/, 'extends BaseCrudService {');
  } else {
    // Pattern B: Add BaseCrudService import before the class
    const classMatch = code.match(/^(class\s+\w+)/m);
    if (classMatch) {
      const classPos = code.indexOf(classMatch[0]);
      // Find a good place to add the import — after the last require statement before the class
      const beforeClass = code.substring(0, classPos);
      const lastRequire = beforeClass.lastIndexOf('require(');
      const insertPos = beforeClass.indexOf('\n', lastRequire) + 1;

      if (insertPos > 0) {
        code = code.substring(0, insertPos) + "\nconst BaseCrudService = require('./base/BaseCrudService');\n" + code.substring(insertPos);
      }

      // Add extends BaseCrudService
      code = code.replace(/class\s+(\w+)\s*\{/, 'class $1 extends BaseCrudService {');
    }
  }
  return code;
}

function addModelRegistration(code, models) {
  if (models.length === 0) return code;

  const registry = buildModelRegistry(models);

  // Check if constructor exists
  const hasConstructor = /constructor\s*\(\)\s*\{/.test(code);

  if (hasConstructor) {
    // Pattern A: constructor already calls super() — replace super call
    const superMatch = code.match(/super\s*\(\s*'([^']+)'\s*,\s*(\{[\s\S]*?\})\s*\)\s*;/);
    if (superMatch) {
      const [fullSuper, name, opts] = superMatch;
      const newSuper = `super('${name}', ${opts}, {\n${registry},\n    })`;
      code = code.replace(fullSuper, newSuper);
    }
  } else {
    // Pattern B: No constructor — add one after class opening brace
    const classMatch = code.match(/class\s+(\w+)(?:\s+extends\s+\w+)?\s*\{/);
    if (classMatch) {
      const className = classMatch[1];
      const insertAfter = code.indexOf(classMatch[0]) + classMatch[0].length;
      const constructorCode = `
  constructor() {
    super('${className}', {}, {
${registry},
    });
  }
`;
      code = code.substring(0, insertAfter) + constructorCode + code.substring(insertAfter);
    }
  }

  return code;
}

// ═══════════════ Main Migration ═══════════════

function migrateFile(filePath) {
  const filename = path.basename(filePath);
  let code = fs.readFileSync(filePath, 'utf8');
  const originalLines = code.split('\n').length;

  // Skip non-class-based services (Pattern C)
  if (!(/class\s+\w+/.test(code) && code.includes('module.exports'))) {
    return { skipped: true, reason: 'not class-based' };
  }

  // Skip already migrated files
  if (code.includes('BaseCrudService')) {
    return { skipped: true, reason: 'already migrated' };
  }

  const isPatternA = code.includes('BaseDomainModule');
  const { models } = getModelNames(code);

  const changes = [];

  // 1. Add BaseCrudService import + extends
  code = addBaseCrudServiceImport(code, isPatternA);
  changes.push(isPatternA ? 'BaseDomainModule → BaseCrudService' : 'added extends BaseCrudService');

  // 2. Add model registration in constructor
  code = addModelRegistration(code, models);
  if (models.length > 0) changes.push(`registered ${models.length} models`);

  // 3. Remove healthCheck
  const hcResult = removeHealthCheck(code);
  if (hcResult.removed) {
    code = hcResult.code;
    changes.push(`removed healthCheck (-${hcResult.linesRemoved} lines)`);
  }

  // 4. Collapse standard CRUD methods
  const createResult = collapseStandardCreate(code);
  code = createResult.code;
  if (createResult.count > 0) changes.push(`${createResult.count} creates → _create()`);

  const getResult = collapseStandardGetById(code);
  code = getResult.code;
  if (getResult.count > 0) changes.push(`${getResult.count} gets → _getById()`);

  const updateResult = collapseStandardUpdate(code);
  code = updateResult.code;
  if (updateResult.count > 0) changes.push(`${updateResult.count} updates → _update()`);

  const listResult = collapseMultiLineList(code);
  code = listResult.code;
  if (listResult.count > 0) changes.push(`${listResult.count} lists → _list()`);

  const newLines = code.split('\n').length;
  const linesSaved = originalLines - newLines;

  return {
    skipped: false,
    code,
    changes,
    originalLines,
    newLines,
    linesSaved,
    isPatternA,
    modelCount: models.length,
  };
}

// ═══════════════ Run ═══════════════

function run() {
  const files = SINGLE_FILE
    ? [SINGLE_FILE]
    : fs
        .readdirSync(SERVICES_DIR)
        .filter(f => f.startsWith('ddd') && f.endsWith('.js'))
        .sort();

  let totalMigrated = 0;
  let totalSkipped = 0;
  let totalLinesSaved = 0;
  let totalCreates = 0;
  let totalGets = 0;
  let totalUpdates = 0;
  let totalLists = 0;
  let totalHealthChecks = 0;
  const errors = [];

  console.log(DRY_RUN ? '=== DRY RUN ===' : '=== APPLYING CHANGES ===');
  console.log(`Processing ${files.length} files...\n`);

  for (const f of files) {
    const filePath = path.join(SERVICES_DIR, f);
    try {
      const result = migrateFile(filePath);

      if (result.skipped) {
        totalSkipped++;
        continue;
      }

      totalMigrated++;
      totalLinesSaved += result.linesSaved;

      // Count specific changes
      for (const c of result.changes) {
        if (c.includes('creates')) totalCreates += parseInt(c) || 0;
        if (c.includes('gets')) totalGets += parseInt(c) || 0;
        if (c.includes('updates')) totalUpdates += parseInt(c) || 0;
        if (c.includes('lists')) totalLists += parseInt(c) || 0;
        if (c.includes('healthCheck')) totalHealthChecks++;
      }

      console.log(
        `  ${result.linesSaved >= 0 ? '✓' : '⚠'} ${f}: ${result.originalLines} → ${result.newLines} lines (${result.linesSaved >= 0 ? '-' : '+'}${Math.abs(result.linesSaved)}) [${result.changes.join(', ')}]`,
      );

      if (!DRY_RUN) {
        // Syntax check before writing
        try {
          new (require('vm').Script)(result.code, { filename: f });
        } catch (syntaxErr) {
          errors.push({ file: f, error: `Syntax error: ${syntaxErr.message}` });
          console.log(`    ✗ SYNTAX ERROR — skipping write: ${syntaxErr.message}`);
          continue;
        }
        fs.writeFileSync(filePath, result.code, 'utf8');
      }
    } catch (err) {
      errors.push({ file: f, error: err.message });
      console.log(`  ✗ ${f}: ERROR — ${err.message}`);
    }
  }

  console.log('\n=== SUMMARY ===');
  console.log(`Migrated: ${totalMigrated}`);
  console.log(`Skipped: ${totalSkipped}`);
  console.log(`Errors: ${errors.length}`);
  console.log(`Total lines saved: ${totalLinesSaved}`);
  console.log(`healthChecks removed: ${totalHealthChecks}`);
  console.log(`CRUD method replacements: creates=${totalCreates}, gets=${totalGets}, updates=${totalUpdates}, lists=${totalLists}`);

  if (errors.length > 0) {
    console.log('\nErrors:');
    for (const e of errors) {
      console.log(`  ${e.file}: ${e.error}`);
    }
  }

  if (DRY_RUN) {
    console.log('\n→ Run with --apply to apply changes');
  } else {
    console.log('\n→ Changes applied. Run syntax check + tests to verify.');
  }
}

run();
